# --- ID3D12Object methods ---

proc getPrivateData*(self: ID3D12Object, guid: pointer, data_size: ptr uint32, data: pointer) =
  type F = proc(this: ID3D12Object, guid: pointer, data_size: ptr uint32, data: pointer): int32 {.stdcall.}
